let s_un = self_@.un_acked_messages(src@);

// `abstractify_seq_of_cpackets_to_set_of_sht_packets` is a `pub open spec fn`
// whose body is `cps.map_values(|cp: CPacket| cp@).to_set()`. Make the unfolding
// explicit so z3 has both ensures-forms equated for r1 and r2 unconditionally —
// these two asserts hold without needing the implication antecedent.
assert(abstractify_seq_of_cpackets_to_set_of_sht_packets(r1@)
    == r1@.map_values(|cp: CPacket| cp@).to_set());
assert(abstractify_seq_of_cpackets_to_set_of_sht_packets(r2@)
    == r2@.map_values(|cp: CPacket| cp@).to_set());

// The proof-fn's ensures is `HYP(r1) && HYP(r2) ==> det_..._equal(r1, r2)`, so the
// individual ensures clauses are NOT free hypotheses in this body — they only hold
// under the implication's antecedent. Gate the bridging assertion behind that
// antecedent with an `if` so it is verified in a context where it actually holds.
if abstractify_seq_of_cpackets_to_set_of_sht_packets(r1@) == s_un
    && outbound_packet_seq_is_valid(r1@)
    && outbound_packet_seq_has_correct_srcs(r1@, src@)
    && s_un == r1@.map_values(|p: CPacket| p@).to_set()
    && CSingleDelivery::packets_are_valid_messages(r1@)
    && abstractify_seq_of_cpackets_to_set_of_sht_packets(r2@) == s_un
    && outbound_packet_seq_is_valid(r2@)
    && outbound_packet_seq_has_correct_srcs(r2@, src@)
    && s_un == r2@.map_values(|p: CPacket| p@).to_set()
    && CSingleDelivery::packets_are_valid_messages(r2@)
{
    // Both r1@'s and r2@'s view-mapped sets equal the common anchor `s_un`,
    // so by transitivity they equal each other. This bridges the two ensures
    // clauses across r1 and r2 so z3 has a single set-equality term tying
    // together the otherwise disjoint `forall|i|` triggers on r1 and r2.
    assert(r1@.map_values(|p: CPacket| p@).to_set()
        == r2@.map_values(|p: CPacket| p@).to_set());
    assert(abstractify_seq_of_cpackets_to_set_of_sht_packets(r1@)
        == abstractify_seq_of_cpackets_to_set_of_sht_packets(r2@));
}
